        </div>
        <h1 class="header-with-anchor-widget" style="-moz-appearance: optimizelegibility; -moz-osx-font-smoothing: antialiased; -webkit-appearance: optimizelegibility; -webkit-font-smoothing: antialiased; appearance: optimizelegibility; color: rgb(64, 64, 64); font-family: 'SF Pro Display', -apple-system-headline, system-ui, -apple-system, BlinkMacSystemFont, 'Segoe UI', Roboto, Helvetica, Arial, sans-serif, 'Apple Color Emoji', 'Segoe UI Emoji', 'Segoe UI Symbol'; font-size: 2em; font-weight: bold; line-height: 1.16em; margin: 1em 0 0.625em 0; position: relative;">
         Ambition\xe2\x80\x99s Gravity
        </h1>
        <div class="captioned-image-container-static" style="font-size: 16px; line-height: 26px; margin: 32px auto;">
         <figure style="margin: 0 auto; width: 100%;">
          <table border="0" cellpadding="0" cellspacing="0" class="image-wrapper" data-component-name="Image2ToDOMStatic" style="mso-padding-alt: 1em 0 1.6em;" width="100%">
           <tbody>
            <tr>
             <td style="text-align: center;">
             </td>
             <td align="left" class="content" style="text-align: center;" width="1200">
              <a class="image-link" href="https://substack.com/redirect/4e939a2c-ab1e-4d32-82cc-9403fabf2a7d?j=eyJ1IjoiOXAwZ3QifQ.gb8J5T7GnA_ZlNuaMZjmlXXepKbqOsa8-6m8ExkRNpU" rel="" style="align-items: center; border: none; display: block; flex-direction: column; height: auto; margin: 0; padding: 0; position: relative; text-decoration: none; width: auto;" target="_blank">
               <img alt="" class="wide-image" data-attrs='{"src":"https://substack-post-media.s3.amazonaws.com/public/images/44f049f8-5737-4cba-aa28-d53e2c8de19a_1200x600.png","srcNoWatermark":null,"fullscreen":null,"imageSize":null,"height":600,"width":1200,"resizeWidth":null,"bytes":null,"alt":null,"title":null,"type":null,"href":null,"belowTheFold":true,"topImage":false,"internalRedirect":null}' height="275" src="https://substackcdn.com/image/fetch/w_2400,c_limit,f_auto,q_auto:good,fl_progressive:steep/https%3A%2F%2Fsubstack-post-media.s3.amazonaws.com%2Fpublic%2Fimages%2F44f049f8-5737-4cba-aa28-d53e2c8de19a_1200x600.png" style="-ms-interpolation-mode: bicubic; border: none !important; display: block; height: auto; margin: 0 auto; margin-bottom: 0; max-width: 100% !important; vertical-align: middle; width: auto !important;" width="550"/>
              </a>
