              <a class="image-link" href="https://substack.com/redirect/b09955a3-60ee-44b7-aa57-fdb14d400811?j=eyJ1IjoiOXAwZ3QifQ.gb8J5T7GnA_ZlNuaMZjmlXXepKbqOsa8-6m8ExkRNpU" rel="" style="align-items: center; border: none; display: block; flex-direction: column; height: auto; margin: 0; padding: 0; position: relative; text-decoration: none; width: auto;" target="_blank">
               <img alt="" class="wide-image" data-attrs='{"src":"https://substack-post-media.s3.amazonaws.com/public/images/73cc13bf-fe2a-412a-bbff-31b38ffb0108_782x409.png","srcNoWatermark":null,"fullscreen":null,"imageSize":null,"height":409,"width":782,"resizeWidth":null,"bytes":null,"alt":null,"title":null,"type":null,"href":null,"belowTheFold":true,"topImage":false,"internalRedirect":null}' height="287.6598465473146" src="https://substackcdn.com/image/fetch/w_1564,c_limit,f_auto,q_auto:good,fl_progressive:steep/https%3A%2F%2Fsubstack-post-media.s3.amazonaws.com%2Fpublic%2Fimages%2F73cc13bf-fe2a-412a-bbff-31b38ffb0108_782x409.png" style="-ms-interpolation-mode: bicubic; border: none !important; display: block; height: auto; margin: 0 auto; margin-bottom: 0; max-width: 100% !important; vertical-align: middle; width: auto !important;" width="550"/>
